20			t.Fatalf("unexpected error parsing flags: %v", err)
21		}
22	
23		pages, err := clearCmd.Flags().GetBool("pages")
24		if err != nil {
25			t.Fatalf("could not get --pages: %v", err)
26		}
27		if !pages {
28			t.Fatalf("expected --pages to be true")
29		}
30	}
